pragma solidity 0.8.20;

contract TeamVestingVault {
    address public owner;

    mapping(address => uint256) public allocation;
    mapping(address => uint256) public releaseTime;
    mapping(address => uint256) public withdrawn;

    error Unauthorized();
    error InvalidAddress();
    error InvalidAmount();
    error NoAllocation();
    error TooEarly();

    event InvestorAdded(address indexed investor, uint256 amount, uint256 unlockTime);
    event Withdrawn(address indexed investor, uint256 amount);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorized();
        _;
    }

    function addInvestor(
        address investor,
        uint256 amount,
        uint256 unlockTime
    ) external onlyOwner {
        if (investor == address(0)) revert InvalidAddress();
        if (amount == 0) revert InvalidAmount();

        allocation[investor] = amount;
        releaseTime[investor] = unlockTime;

        emit InvestorAdded(investor, amount, unlockTime);
    }

    function withdraw() external {
        uint256 amount = allocation[msg.sender];
        if (amount == 0) revert NoAllocation();
        if (block.timestamp < releaseTime[msg.sender]) revert TooEarly();

        allocation[msg.sender] = 0;
        withdrawn[msg.sender] += amount;

        emit Withdrawn(msg.sender, amount);
    }
}
